	merged := []string{}
	i := 0
	for i < len(paragraphs) {
		para := paragraphs[i]
		var lines []string
		if strings.Contains(para, "\n") {
			lines = strings.Split(para, "\n")
		} else {
			lines = []string{para}
		}

		if anyTableLine(lines) {
			blockParts := []string{para}
			j := i + 1
			for j < len(paragraphs) {
				var nextLines []string
				if strings.Contains(paragraphs[j], "\n") {
					nextLines = strings.Split(paragraphs[j], "\n")
				} else {
					nextLines = []string{paragraphs[j]}
				}
				if anyTableLine(nextLines) {
					blockParts = append(blockParts, paragraphs[j])
					j++
				} else {
					break
				}
			}
			merged = append(merged, strings.Join(blockParts, separator))
			i = j
			continue
		}

		if anyListLine(lines) {
			blockParts := []string{para}
			j := i + 1
			for j < len(paragraphs) {
				var nextLines []string
				if strings.Contains(paragraphs[j], "\n") {
