func trimOverlapTail(prevContent string, overlapChars int) string {
	if len(prevContent) <= overlapChars {
		return prevContent
	}
	tail := prevContent[len(prevContent)-overlapChars:]
	boundaryChar := string(prevContent[len(prevContent)-overlapChars-1])
	firstTailChar := string(tail[0])
	if strings.TrimSpace(boundaryChar) != "" && strings.TrimSpace(firstTailChar) != "" {
		spacePos := strings.Index(tail, " ")
		if spacePos != -1 {
			tail = tail[spacePos+1:]
		}
	}
	return tail
