func (dl *DocumentLoader) LoadIMAP(uri string, includeAttachments bool, limit *int) ([]DocumentChunk, error) {
	transport := NewImapTransport()
	extractor := NewEmailExtractor(includeAttachments)

	var allChunks []DocumentChunk
	messages, err := transport.FetchMessages(uri, limit)
	if err != nil {
		return nil, fmt.Errorf("load_imap fetch: %w", err)
	}
	for _, result := range messages {
		text, err := extractor.Extract(result.Data, result.SourcePath)
		if err != nil {
			log.Printf("load_imap: skipping message %s: %v", result.SourcePath, err)
			continue
		}
		if strings.TrimSpace(text) == "" {
			continue
		}
		name := result.SourcePath
		if name == "" {
			name = "email"
		}
		chunks, err := chunkDocument(name, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext)
		if err != nil {
			log.Printf("load_imap: skipping message %s: %v", result.SourcePath, err)
			continue
		}
		enriched, err := dl.enrich(chunks)
		if err != nil {
			log.Printf("load_imap: enrich error %s: %v", result.SourcePath, err)
			continue
		}
		allChunks = append(allChunks, enriched...)
	}
	return allChunks, nil
}

func (dl *DocumentLoader) LoadFromDB(connection interface{}, queries [][2]string, docType string) ([]DocumentChunk, error) {
	transport := NewSqlQueryTransport(connection)
	extractor, err := dl.findExtractor(docType)
	if err != nil {
		return nil, fmt.Errorf("load_from_db find extractor: %w", err)
	}
	provenance := dbProvenance(connection)
	var allChunks []DocumentChunk

	for _, pair := range queries {
		name, sql := pair[0], pair[1]
		result, err := transport.Fetch(fmt.Sprintf("sqlquery://%s", name), sql)
		if err != nil {
			return nil, fmt.Errorf("load_from_db fetch %s: %w", name, err)
		}
		text, err := extractor.Extract(result.Data, name)
		if err != nil {
			return nil, fmt.Errorf("load_from_db extract %s: %w", name, err)
		}
		chunks, err := chunkDocument(name, text, dl.MinChunkSize, dl.MaxChunkSize, dl.OverflowMargin, dl.EnrichContext, dl.IncludeDocName)
		if err != nil {
			return nil, fmt.Errorf("load_from_db chunk %s: %w", name, err)
		}
		chunks, err = extractor.Annotate(chunks, result.Data, name)
		if err != nil {
			return nil, fmt.Errorf("load_from_db annotate %s: %w", name, err)
		}
		for i := range chunks {
			if chunks[i].SourceDetail == nil {
				chunks[i].SourceDetail = map[string]interface{}{}
			}
			chunks[i].SourceDetail["query"] = sql
			for k, v := range provenance {
				chunks[i].SourceDetail[k] = v
			}
		}
		enriched, err := dl.enrich(chunks)
		if err != nil {
			return nil, fmt.Errorf("load_from_db enrich %s: %w", name, err)
		}
		allChunks = append(allChunks, enriched...)
	}
	return allChunks, nil
}

