	uri, _ := sourceConfig["uri"].(string)

	loader := NewDocumentLoader(
		WithMinChunkSize(idx.minChunk),
		WithMaxChunkSize(idx.maxChunk),
		WithEnrichContext(true),
		WithIncludeDocName(false),
	)

	if sourceType == "directory" {
		extensions, _ := sourceConfig["extensions"].([]string)
		recursive := true
		if v, ok := sourceConfig["recursive"].(bool); ok {
			recursive = v
		}
		maxFiles := 1000
		if v, ok := sourceConfig["max_files"].(int); ok {
			maxFiles = v
		}
		crawler := NewDirectoryCrawler(extensions, recursive, maxFiles)
		return loader.LoadCrawl(uri, crawler)
	}

	if sourceType == "github" {
		token, _ := sourceConfig["token"].(string)
		branch, _ := sourceConfig["branch"].(string)
		extensions, _ := sourceConfig["extensions"].([]string)
		maxFiles := 2000
		if v, ok := sourceConfig["max_files"].(int); ok {
			maxFiles = v
		}
		crawler := NewGitHubCrawler(token, branch, extensions, maxFiles)
		return loader.LoadCrawl(uri, crawler)
	}

	if sourceType == "web" {
		maxPages := 100
		if v, ok := sourceConfig["max_pages"].(int); ok {
			maxPages = v
		}
		maxDepth := 3
		if v, ok := sourceConfig["max_depth"].(int); ok {
			maxDepth = v
		}
		sameDomain := true
		if v, ok := sourceConfig["same_domain"].(bool); ok {
			sameDomain = v
		}
		crawler := NewWebCrawler(maxPages, maxDepth, sameDomain)
		return loader.LoadCrawl(uri, crawler)
	}

	if sourceType == "http" {
		return loader.Load(uri)
	}

	return nil, fmt.Errorf("unknown source type: %q", sourceType)
}
